export function getToolBySlug(slug: string): Tool | undefined {
  return tools.find((t) => t.slug === slug)
}

export function getToolsByCategory(cat: string): Tool[] {
  if (cat === "all") return tools
  return tools.filter((t) => t.category === cat)
}
